import pandas as pd

df = pd.DataFrame({
    'full_name': ['Alice Smith', 'Bob Jones', 'Charlie Brown']
})

# Method 1: str.split with expand
df[['first_name', 'last_name']] = (
    df['full_name'].str.split(' ', expand=True)
)
print(df)

# Method 2: apply returning Series with multiple values
def parse_name(name):
    parts = name.split()
    return pd.Series({
        'first': parts[0],
        'last': parts[-1],
        'initials': parts[0][0] + parts[-1][0]
    })

df2 = df['full_name'].apply(parse_name)
print(df2)

import pandas as pd

df = pd.DataFrame({
    'email': ['alice@gmail.com', 'bob@company.co.uk', 'charlie@yahoo.com']
})

# apply on a Series (element-wise)
df['domain'] = df['email'].apply(lambda x: x.split('@')[1])
df['provider'] = df['domain'].apply(
    lambda d: d.split('.')[0].title()
)
print(df)

# apply on DataFrame (row-wise with axis=1)
df2 = pd.DataFrame({
    'length': [10, 20, 15],
    'width': [5, 8, 6]
})
df2['area'] = df2.apply(
    lambda row: row['length'] * row['width'], axis=1
)
print(df2)

