import pandas as pd

def add_total(df):
    df['total'] = df['math'] + df['english']
    return df

def add_grade(df, threshold=160):
    df['grade'] = df['total'].apply(
        lambda x: 'A' if x >= threshold else 'B'
    )
    return df

df = pd.DataFrame({
    'name': ['Alice', 'Bob', 'Carol'],
    'math': [90, 75, 88],
    'english': [85, 80, 92]
})

result = (
    df
    .pipe(add_total)
    .pipe(add_grade, threshold=170)
)
print(result)

