import pandas as pd
import numpy as np

def add_total(df, col_a, col_b):
    return df.assign(total=df[col_a] + df[col_b])

def flag_outliers(df, col, threshold=2):
    mean, std = df[col].mean(), df[col].std()
    return df.assign(is_outlier=lambda x: abs(x[col] - mean) > threshold * std)

df = pd.DataFrame({'a': [1, 2, 3, 100], 'b': [10, 20, 30, 40]})
result = (
    df
    .pipe(add_total, 'a', 'b')
    .pipe(flag_outliers, 'total')
)
print(result)
